class Solution(object):
    def countRectangles(self, rectangles, points):
        from collections import defaultdict
        import bisect
        height_widths = defaultdict(list)
        for l, h in rectangles:
            height_widths[h].append(l)
        for h in height_widths:
            height_widths[h].sort()
        result = []
        for x, y in points:
            count = 0
            for h in range(y, 101):
                if h in height_widths:
                    idx = bisect.bisect_left(height_widths[h], x)
                    count += len(height_widths[h]) - idx
            result.append(count)
        return result
